using BookSeller.Domain;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace BookSeller.Domain.Tests;

[TestClass]
public sealed class ValidateBookAuthoredTests
{
    [TestMethod]
    public void Book_WithEmptyIsbn_IsRejected()
    {
        Assert.ThrowsException<System.ArgumentException>(() => new Book("", "Title", "Author", 10m));
    }

    [TestMethod]
    public void Book_WithNegativePrice_IsRejected()
    {
        Assert.ThrowsException<System.ArgumentOutOfRangeException>(() => new Book("isbn-1", "Title", "Author", -1m));
    }

    [TestMethod]
    public void Book_WithZeroPrice_IsValid()
    {
        var book = new Book("isbn-1", "Title", "Author", 0m);
        Assert.AreEqual(0m, book.Price);
    }
}
